# ============================================
# BATCH SCHEDULE
# ============================================
# Format: (date_str, start_idx, end_idx)
# Triggered by Zoho Flow via workflow_dispatch
# Remaining leads (index 8000-9916) are PENDING - do not use, no date assigned
SCHEDULE = [
    ("2026-07-21", 0,    2000),  # 21 July - 2,000 leads
    ("2026-07-22", 2000, 4000),  # 22 July - 2,000 leads
    ("2026-07-23", 4000, 6000),  # 23 July - 2,000 leads
    ("2026-07-24", 6000, 8000),  # 24 July - 2,000 leads
    # 1916 leads remaining (index 8000-9916) - PENDING, date TBD, DO NOT USE
]

# ============================================
# STEP 0: Guard against running twice successfully on the same day
# ============================================
def already_succeeded_today(today_str):
    """
    Checks GitHub Actions run history for this workflow. If a run for
    today already completed successfully, we skip so Zoho Flow retriggers
    (or manual re-runs) don't double-process / double-tag the same leads.
    """
    if not (GITHUB_TOKEN and GITHUB_REPOSITORY and GITHUB_WORKFLOW):
        print("GitHub context not available - skipping same-day duplicate check.")
        return False

    url = f"https://api.github.com/repos/{GITHUB_REPOSITORY}/actions/runs"
    headers = {
        "Authorization": f"Bearer {GITHUB_TOKEN}",
        "Accept": "application/vnd.github+json"
    }
    params = {"status": "success", "per_page": 30}

    try:
        resp = requests.get(url, headers=headers, params=params, timeout=30)
        resp.raise_for_status()
        runs = resp.json().get("workflow_runs", [])
    except Exception as e:
        print(f"Warning: could not check previous runs ({e}). Proceeding anyway.")
        return False

    for run in runs:
        if run.get("name") != GITHUB_WORKFLOW:
            continue
        if str(run.get("id")) == str(GITHUB_RUN_ID):
            continue  # ignore the current run itself
        created_at = run.get("created_at", "")  # e.g. "2026-07-21T09:15:00Z"
        if created_at.startswith(today_str):
            print(f"Found a successful run already completed today ({run.get('id')}).")
            return True

    return False

# ============================================
# STEP 1: Get Access Token
# ============================================
def get_access_token():
    url = "https://accounts.zoho.in/oauth/v2/token"
    params = {
        "refresh_token": REFRESH_TOKEN,
        "client_id":     CLIENT_ID,
        "client_secret": CLIENT_SECRET,
        "grant_type":    "refresh_token"
    }
    response = requests.post(url, params=params)
    token = response.json().get("access_token")
    if not token:
        raise Exception("Failed to get access token: " + str(response.json()))
    print("Access token received")
    return token

# ============================================
# STEP 2: Update Leads in Batches of 100
# ============================================
def update_leads(token, lead_ids):
    headers = {
        "Authorization": f"Zoho-oauthtoken {token}",
        "Content-Type": "application/json"
    }
    url = "https://www.zohoapis.in/crm/v2/Leads"
    total_updated = 0

    for i in range(0, len(lead_ids), API_BATCH_SIZE):
        batch = lead_ids[i:i + API_BATCH_SIZE]
        payload = {
            "data": [
                {
                    "id": lead_id.replace("zcrm_", ""),
                    "RM_Template_Name1": RM_TEMPLATE_NAME
                }
                for lead_id in batch
            ]
        }
        response = requests.put(url, headers=headers, json=payload)
        result = response.json()
        success = sum(1 for r in result.get("data", []) if r.get("code") == "SUCCESS")
        total_updated += success
        print(f"  Batch {i//API_BATCH_SIZE + 1} -> {success}/{len(batch)} updated")

    return total_updated

# ============================================
# MAIN RUN
# ============================================
def main():
    print("\nStarting Zoho CRM Lead Update...")
    print("=" * 45)

    today = datetime.now(timezone.utc).strftime("%Y-%m-%d")
    print(f"Running on: {today}")

    todays_batch = None
    for date_str, start_idx, end_idx in SCHEDULE:
        if date_str == today:
            todays_batch = (start_idx, end_idx)
            break

    if not todays_batch:
        print(f"No schedule found for today ({today}). Nothing to do.")
        return

    if already_succeeded_today(today):
        print(f"Today's batch ({today}) already completed successfully. Skipping to avoid duplicate run.")
        return

    start_idx, end_idx = todays_batch
    todays_leads = ALL_LEAD_IDS[start_idx:end_idx]

    print(f"Processing leads {start_idx+1} to {end_idx} ({len(todays_leads)} leads)")
    print(f"Template: {RM_TEMPLATE_NAME}")
    print("=" * 45)

    token = get_access_token()
    total_updated = update_leads(token, todays_leads)

    print(f"\nDone! Updated {total_updated} leads today")
    print(f"Progress: leads {start_idx+1}-{end_idx} out of 8,000 scheduled")
    print(f"Pending: 1916 leads (index 8000-9916) - DO NOT USE, date TBD")
    print("=" * 45)

    if len(todays_leads) > 0 and total_updated == 0:
        raise Exception("No leads were updated - marking run as failed so retry can happen")


if __name__ == "__main__":
    main()
